#[async_trait]
impl<R: DataExportProjectionRepository> DataExportEventHandler for DataExportProjector<R> {

    async fn on_created(&self, event: DataExportCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = DataExportProjection::new(
            event.id,
            event.user_id,
            event.requested_by,
            event.requested_at,
            event.status,
            event.file_path,
            event.file_url,
            event.expires_at,
            event.completed_at,
            event.record_count,
            event.format,
            event.justification,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: DataExportUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.requested_by = event.requested_by;
            projection.requested_at = event.requested_at;
            projection.status = event.status;
            projection.file_path = event.file_path;
            projection.file_url = event.file_url;
            projection.expires_at = event.expires_at;
            projection.completed_at = event.completed_at;
            projection.record_count = event.record_count;
            projection.format = event.format;
            projection.justification = event.justification;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: DataExportDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

